qry:select.qry:xquery:
for $r in SQL(' select WRN.c_resolver, WRN.c_rol, OA.d_role, OA.d_color from WRK01_WF as WF, WRK01_PROCESS as WP, WRK01_NODES as WN, WRK01_ROLES_NODE as WRN,
WRK05_ORGANIGRAMAS as OG, WRK05_ORGANIGRAMAS as OP, WRK05_ROLES as OA join WF.oi_wf inner WP.oi_wf, WP.oi_process inner WN.oi_process, WN.oi_node inner WRN.oi_node, WF.oi_organigrama inner OG.oi_organigrama, OP.c_organigrama inner OG.c_organigrama, OP.e_version inner OG.e_version_pub, OP.oi_organigrama inner OA.oi_organigrama, OA.c_role inner WRN.c_rol where OP.l_automatica=1 and WRN.c_resolver != \'NO\' and WRN.c_resolver != \'\' and IsNotNull(WRN.c_resolver) and WN.oi_node = {$SOURCE/@oi_node}
')/ROWS/ROW

for $r in SQL(' select T.oi_thread from wrk02_threads as T,wrk02_instances as I join T.oi_instance inner I.oi_instance
where I.c_estado_ej=\'E\' and T.c_estado=\'E\' and T.oi_instance={%= $SOURCE/@oi_instance %}
')/ROWS/ROW

head.script:
						var SelectedMODE="TASK";

function Replace(strin, strfnd, strrpl)
{
var strout="", lastpos;

for (lastpos=0, pos=strin.indexOf(strfnd); pos!=-1; lastpos=pos+strfnd.length, pos=strin.indexOf(strfnd,lastpos))
{                
strout+=strin.substr(lastpos,pos-lastpos);
strout+=strrpl;
} 		
strout+=strin.substr(lastpos);

return strout;
} 

function GenerateWIKI(strin, parentPath)
{
var t,d,mode,mode2=0;
var sections=new Array();
var new_section=null;
var mode="";
var lineas="";
var text;

lineas=Replace(strin,"\r\n","\n").split("\n");

for (t=0; t{#CHAR.LT#}lineas.length; t++)
{
mylin=lineas[t];

x=0; mylintrim=mylin;
while(mylintrim.length{#CHAR.GT#}0 {#CHAR.amp#}{#CHAR.amp#} mylintrim.charCodeAt(0){#CHAR.LT#}=32 {#CHAR.amp#}{#CHAR.amp#} mylintrim.charCodeAt(0){#CHAR.GT#}0) { mylintrim=mylintrim.substr(1); x++; }
mylintrim=Trim(mylintrim)

if (mode2!=0)
{
if (mylintrim=="{#CHAR.LT#}/code{#CHAR.GT#}") mode2=0;
if (mylintrim=="{#CHAR.LT#}/file{#CHAR.GT#}") mode2=0;
if (mylintrim=="{#CHAR.LT#}/nowiki{#CHAR.GT#}") mode2=0;
}

if (mode2!=0)
text+=(text!=""?"\n":"")+mylin;

if (mode2==0)
{
if (mylin.length==0)
new_section=null;
else
{
mode=1; //comun
if (mylin.substr(0,2)=="  ")
{
	if ((mylintrim.substr(0,1)!="*") {#CHAR.amp#}{#CHAR.amp#} (mylintrim.substr(0,1)!="-")) mode=2; //CODE
	                                                             else mode=3; //LISTA
} else
{
	for (HeadMode=6; HeadMode{#CHAR.GT#}0; HeadMode--)
		if ((mylin.substr(0,HeadMode+1)=="======".substr(0,HeadMode)+" ") {#CHAR.amp#}{#CHAR.amp#} (mylin.substr(mylin.length-(HeadMode+1),HeadMode+1)==" "+"======".substr(0,HeadMode)))
			mode=4; //HEAD

	if (mylin.substr(0,4)=="----")
		mode=6; //LINEA

	if (mylin.substr(0,1)=="{#CHAR.GT#}")
		mode=8; //DIALOGO

	if ((mylin.substr(0,1)=="|") || (mylin.substr(0,1)=="^"))
		mode=9; //TABLA
}

if (mode==1)
{
	if (mylintrim=="{#CHAR.LT#}code{#CHAR.GT#}")             { mode2= 2; text=""; continue; }
	if (mylintrim.substr(0,6)=="{#CHAR.LT#}code ") { mode2= 2; text=""; continue; }
	if (mylintrim=="{#CHAR.LT#}file{#CHAR.GT#}")             { mode2= 5; text=""; continue; }
	if (mylintrim=="{#CHAR.LT#}nowiki{#CHAR.GT#}")           { mode2= 7; text=""; continue; }

	if (mylintrim=="{#CHAR.LT#}/nowiki{#CHAR.GT#}") 
	{ 
		mode=7; //CODE
		mylintrim=text;
	}
	if (mylintrim=="{#CHAR.LT#}/code{#CHAR.GT#}") 
	{ 
		mode=2; //CODE
		mylintrim=text;
	}
	if (mylintrim=="{#CHAR.LT#}/file{#CHAR.GT#}")
	{ 
		mode=5; //FILE
		mylintrim=text;
	}
}

//controlo que el modo anterior sea igual al actual
if (new_section!=null)
	if (new_section.mode!=mode) 
		new_section=null; 

//creo el modo si este no existe
if (new_section==null)
{
	new_section=new Object();
	new_section.mode=mode;
	new_section.HTML="";
	new_section.Level=0;
	new_section.Items=null;
	new_section.Start=t;
	new_section.End=t;

	sections[sections.length]=new_section;
} else
	new_section.End=t;


//Analizo los distintos modos
switch(mode)
{
	case 1: //Texto WIKI
		new_section.HTML+=WIKIEncode(t, x, mylintrim,'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/")+" ";
	break;
	case 7: //Texto NO WIKI
		new_section.HTML+=HTMLEncode(mylintrim)+" "; 
	break;

	case 2: //Code
	case 5: //File
		new_section.HTML+=(new_section.HTML!=""?"{#CHAR.LT#}br/{#CHAR.GT#}":"")+HTMLEncode(mylintrim)+" ";
	break;

	case 10: //Nomad Code
		new_section.HTML+=(new_section.HTML!=""?"\n":"")+mylintrim+" ";
	break;

	case 9: //Tabla
		if (new_section.Items==null) new_section.Items=new Array();
		new_section.Items[new_section.Items.length]=mylin;
	break;

	case 8: //Dialogo
		for (d=0; d{#CHAR.LT#}mylin.length {#CHAR.amp#}{#CHAR.amp#} mylin.substr(d,1)=='{#CHAR.GT#}'; d++);

		newItem=new Object();
		newItem.spaces=d;
		newItem.HTML  =WIKIEncode(t, d, Trim(mylin.substr(d)),'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/");

		//Agrego el Item
		if (new_section.Items==null) new_section.Items=new Array();
		new_section.Items[new_section.Items.length]=newItem;
	break;

	case 3: //Lista 
		newItem=new Object();
		newItem.spaces=mylin.indexOf(mylintrim);
		newItem.mode  =mylintrim.substr(0,1);
		newItem.HTML  =WIKIEncode(t, newItem.spaces+1, mylintrim.substr(1),'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/");

		//Agrego el Item
		if (new_section.Items==null) new_section.Items=new Array();
		new_section.Items[new_section.Items.length]=newItem;
	break;

	case 4: //Cabezera
		for (HeadMode=6; HeadMode{#CHAR.GT#}0; HeadMode--)
			if ((mylin.substr(0,HeadMode+1)=="======".substr(0,HeadMode)+" ") {#CHAR.amp#}{#CHAR.amp#} (mylin.substr(mylin.length-(HeadMode+1),HeadMode+1)==" "+"======".substr(0,HeadMode)))
			{
				new_section.Level=(7-HeadMode);
				new_section.HTML+=WIKIEncode(t, HeadMode+1, mylin.substr(HeadMode+1,mylin.length-(HeadMode+1)*2),'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/")+" ";
			}
		new_section=null;
	break;

	case 6: //LINEA
	break;
}

}
}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////
// Genero el HTML
var HTMLresult="{#CHAR.LT#}div class='dokuwiki'{#CHAR.GT#}";
var section,Niveles,n,d,Item,newNivel, divLevel=0, linStart=0;

for (t=0; t{#CHAR.LT#}sections.length; t++)
{
section=sections[t];
switch(section.mode)
{
case 1: //Texto WIKI
case 7: //Texto NO WIKI
	HTMLresult+="{#CHAR.LT#}p{#CHAR.GT#}"+section.HTML+"{#CHAR.LT#}/p{#CHAR.GT#}";
break;

case 2: //Code
	HTMLresult+="{#CHAR.LT#}pre class='code' {#CHAR.GT#}"+section.HTML+"{#CHAR.LT#}/pre{#CHAR.GT#}";  
break;

case 5: //File
	HTMLresult+="{#CHAR.LT#}pre class='file' {#CHAR.GT#}"+section.HTML+"{#CHAR.LT#}/pre{#CHAR.GT#}";  
break;

case 9: //Tabla
	HTMLresult+="{#CHAR.LT#}table class='inline' {#CHAR.GT#}";  
	for (d=0; d{#CHAR.LT#}section.Items.length; d++)
	{
		HTMLresult+="{#CHAR.LT#}tr{#CHAR.GT#}";

		Item=section.Items[d];

		x=0;
		while (Item.length{#CHAR.GT#}1)
		{
			if (Item.substr(0,1)=="^") mode=1;
			if (Item.substr(0,1)=="|") mode=0;

			Item=Item.substr(1); mylin=""; x++; x2=x;
			while (Item.substr(0,1)!="|" {#CHAR.amp#}{#CHAR.amp#} Item.substr(0,1)!="^" {#CHAR.amp#}{#CHAR.amp#} Item.length{#CHAR.GT#}0)
			{
				mylin+=Item.substr(0,1); Item=Item.substr(1); x++;
			}

			count=0;
			while ((Item.substr(count,1)=="|" || Item.substr(count,1)=="^") {#CHAR.amp#}{#CHAR.amp#} Item.length{#CHAR.GT#}count) count++;
			if (count) { Item=Item.substr(count-1); x+=count-1; }

			HTMLresult+=mode?"{#CHAR.LT#}th":"{#CHAR.LT#}td";
			if (count{#CHAR.GT#}1) HTMLresult+=" colspan='"+count+"' ";        
			if (mylin.substr(0,1)!=" ") HTMLresult+=" class='leftalign' "; else
			if (mylin.substr(mylin.length-1,1)!=" ") HTMLresult+=" class='rightalign' "; else
			if (mylin.substr(0,2)=="  ") HTMLresult+=" align='centeralign' ";

			while(mylin.length{#CHAR.GT#}0 {#CHAR.amp#}{#CHAR.amp#} mylin.charCodeAt(0){#CHAR.LT#}=32 {#CHAR.amp#}{#CHAR.amp#} mylin.charCodeAt(0){#CHAR.GT#}0) { mylin=mylin.substr(1); x2++; }

			HTMLresult+="{#CHAR.GT#}";
			HTMLresult+=WIKIEncode(section.Start+d, x2, Trim(mylin),'parent.Ctrl("'+this.m_ID+'").',"../images/Wiki/");
			HTMLresult+=mode?"{#CHAR.LT#}/th{#CHAR.GT#}":"{#CHAR.LT#}/td{#CHAR.GT#}";

		}

		HTMLresult+="{#CHAR.LT#}/tr{#CHAR.GT#}";  
	}
	HTMLresult+="{#CHAR.LT#}/table{#CHAR.GT#}";  
break;

case 3: //Lista
	Niveles=new Array();
	for (d=0; d{#CHAR.LT#}section.Items.length; d++)
	{
		Item=section.Items[d];

		newNivel=null;
		for (n=0; n{#CHAR.LT#}Niveles.length; n++)
		{
			if (Niveles[n].spaces{#CHAR.GT#}Item.spaces)
			{
				while (Niveles.length{#CHAR.GT#}n)
				{
					if (Niveles[Niveles.length-1].mode=="*") HTMLresult+="{#CHAR.LT#}/ul{#CHAR.GT#}";
					if (Niveles[Niveles.length-1].mode=="-") HTMLresult+="{#CHAR.LT#}/ol{#CHAR.GT#}";
					Niveles.length--;
				}
			} else
			if (Niveles[n].spaces==Item.spaces)
				newNivel=Niveles[n];
		}

		if (newNivel==null)
		{
			Niveles[Niveles.length]=newNivel=Item;
			if (newNivel.mode=="*") HTMLresult+="{#CHAR.LT#}ul{#CHAR.GT#}";
			if (newNivel.mode=="-") HTMLresult+="{#CHAR.LT#}ol{#CHAR.GT#}";
		}
		HTMLresult+="{#CHAR.LT#}li{#CHAR.GT#}{#CHAR.LT#}div class='li'{#CHAR.GT#}"+Item.HTML+"{#CHAR.LT#}/div{#CHAR.GT#}{#CHAR.LT#}/li{#CHAR.GT#}";
	}
	while (Niveles.length{#CHAR.GT#}0)
	{   
		if (Niveles[Niveles.length-1].mode=="*") HTMLresult+="{#CHAR.LT#}/ul{#CHAR.GT#}";
		if (Niveles[Niveles.length-1].mode=="-") HTMLresult+="{#CHAR.LT#}/ol{#CHAR.GT#}";
		Niveles.length--;
	}

break;

case 8: //Dialogo 
	Niveles=0;

	for (d=0; d{#CHAR.LT#}section.Items.length; d++)
	{
		Item=section.Items[d];

		while(Niveles{#CHAR.GT#}Item.spaces)
		{
				HTMLresult+="{#CHAR.LT#}/div{#CHAR.GT#}{#CHAR.LT#}/blockquote{#CHAR.GT#}";
				Niveles--;
		}

		while(Niveles{#CHAR.LT#}Item.spaces)
		{
				HTMLresult+="{#CHAR.LT#}blockquote{#CHAR.GT#}{#CHAR.LT#}div class='no'{#CHAR.GT#}";
				Niveles++;
		}
		HTMLresult+=Item.HTML;
	}

	while (Niveles{#CHAR.GT#}0)
	{   
		HTMLresult+="{#CHAR.LT#}/div{#CHAR.GT#}{#CHAR.LT#}/blockquote{#CHAR.GT#}";
		Niveles--;
	}
break;

case 4: //Cabecera
	if (divLevel!=0) HTMLresult+="{#CHAR.LT#}/div{#CHAR.GT#}{#CHAR.LT#}/div{#CHAR.GT#}";
	divLevel=section.Level;
	linStart=section.Start;
	HTMLresult+="{#CHAR.LT#}div class='secedit' {#CHAR.GT#}";
	HTMLresult+="{#CHAR.LT#}H"+divLevel+"{#CHAR.GT#}"+section.HTML+"{#CHAR.LT#}/H"+divLevel+"{#CHAR.GT#}";
	HTMLresult+="{#CHAR.LT#}div class='level"+divLevel+"' {#CHAR.GT#}";
break;

case 6: //Linea
	HTMLresult+="{#CHAR.LT#}hr/{#CHAR.GT#}";
break;
}
}

if (divLevel!=0) HTMLresult+="{#CHAR.LT#}/div{#CHAR.GT#}{#CHAR.LT#}/div{#CHAR.GT#}";
HTMLresult+="{#CHAR.LT#}/div{#CHAR.GT#}";


return HTMLresult;
}

function amp()
{
return String.fromCharCode(38);
}

