function ShowMoreLog(obj)
{
var oi_log=obj.getAttribute("nmd-log");        

var objDIV=document.getElementById("DIV_HEAD");     
var oi_instance=objDIV.getAttribute("nmd-instance");

objI=document.getElementById("backLoad");    
