function ObjWiki()
{
this.GetWikiText=function()
{
  var t;       
  var obj;
  var str="";

t=0;
do     
{
obj=document.getElementById("TXT_"+t);
if (obj) str+=obj.value;
t++;
} while (obj);

return GenerateWIKI(str,"XXX");
}
}

